#include <bits/stdc++.h>
using namespace std;
string s1,s2;
int p[26];
int dfs(int l,int r,int x,int y){
    if(l==r && x==y && s1[l]==s2[x])
        return 1;
    if(s1[l]!=s2[y] || p[s1[l+1]-'a']<x || p[s1[l+1]-'a']>=y)
        return 0;
    if(p[s1[l+1]-'a']==y-1)
        return dfs(l+1,r,x,y-1)*2;
    else
        return dfs(l+1,l+p[s1[l+1]-'a']-x+1,x,p[s1[l+1]-'a'])*dfs(l+p[s1[l+1]-'a']-x+2,r,p[s1[l+1]-'a']+1,y-1);
}
int main(){
    cin>>s1>>s2;
    for(int i=0;i<s2.size();i++)
        p[s2[i]-'a']=i;
    printf("%d",dfs(0,s1.size()-1,0,s2.size()-1));
    return 0;
}
